import{_ as i,o as t,c as o,ag as a}from"./chunks/framework.BKDXG6j6.js";const p=JSON.parse('{"title":"XML Views","description":"","frontmatter":{},"headers":[],"relativePath":"ui/xml.md","filePath":"ui/xml.md","lastUpdated":null}'),s={name:"ui/xml.md"};function r(c,e,n,l,d,h){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="xml-views" tabindex="-1">XML Views <a class="header-anchor" href="#xml-views" aria-label="Permalink to &quot;XML Views&quot;">​</a></h1><p>The legacy, imperative way of building UIs in Android relies on XML layouts and View classes (e.g., <code>TextView</code>, <code>RecyclerView</code>, <code>ConstraintLayout</code>).</p><h2 id="key-xml-concepts" tabindex="-1">Key XML Concepts <a class="header-anchor" href="#key-xml-concepts" aria-label="Permalink to &quot;Key XML Concepts&quot;">​</a></h2><h3 id="_1-view-hierarchies" tabindex="-1">1. View Hierarchies <a class="header-anchor" href="#_1-view-hierarchies" aria-label="Permalink to &quot;1. View Hierarchies&quot;">​</a></h3><p>XML layouts are structured as trees.</p><ul><li>Avoid deep hierarchies as they negatively impact measurement and drawing performance.</li><li><strong>ConstraintLayout</strong> is preferred to flatten the view hierarchy, allowing complex layouts without nesting view groups.</li></ul><h3 id="_2-viewbinding" tabindex="-1">2. ViewBinding <a class="header-anchor" href="#_2-viewbinding" aria-label="Permalink to &quot;2. ViewBinding&quot;">​</a></h3><p>Replaces <code>findViewById</code>, providing null safety and type safety.</p><ul><li>It generates a binding class for each XML layout.</li><li>Directly links to the views via their IDs, avoiding runtime crashes.</li></ul><h3 id="_3-recyclerview" tabindex="-1">3. RecyclerView <a class="header-anchor" href="#_3-recyclerview" aria-label="Permalink to &quot;3. RecyclerView&quot;">​</a></h3><p>Essential for displaying lists.</p><ul><li>Avoids memory exhaustion by recycling off-screen <code>ViewHolder</code> views.</li><li>Requires an <code>Adapter</code> (creates ViewHolders and binds data) and a <code>LayoutManager</code> (positions items).</li><li>Use <code>ListAdapter</code> with <code>DiffUtil</code> for calculating list changes efficiently on a background thread and animating the differences.</li></ul><h3 id="_4-custom-views" tabindex="-1">4. Custom Views <a class="header-anchor" href="#_4-custom-views" aria-label="Permalink to &quot;4. Custom Views&quot;">​</a></h3><p>You can extend existing views (<code>TextView</code>) or <code>View</code>/<code>ViewGroup</code> directly.</p><ul><li>Override <code>onMeasure()</code> to dictate the view&#39;s size.</li><li>Override <code>onDraw()</code> using a <code>Canvas</code> for custom graphics.</li><li>Extract custom attributes into <code>attrs.xml</code> for XML configuration.</li></ul><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Accessibility</strong>: Always use <code>android:contentDescription</code> on ImageViews for TalkBack support. Use <code>minHeight=&quot;48dp&quot;</code> for touch targets.</li><li><strong>Styles and Themes</strong>: Do not hardcode colors in XML. Use <code>?attr/colorPrimary</code> or <code>@style/MyCustomText</code>. Extract common styles into <code>styles.xml</code>.</li><li><strong>Strings</strong>: Never hardcode text strings. Use <code>@string/my_string</code> to support localization.</li></ol><h2 id="interview-questions" tabindex="-1">Interview Questions <a class="header-anchor" href="#interview-questions" aria-label="Permalink to &quot;Interview Questions&quot;">​</a></h2><p><strong>Q: What is the difference between <code>View.GONE</code> and <code>View.INVISIBLE</code>?</strong><em>Answer:</em> <code>View.INVISIBLE</code> hides the view, but it still takes up space in the layout hierarchy. <code>View.GONE</code> completely removes the view from the layout calculations, collapsing the space it previously occupied.</p><p><strong>Q: Explain how <code>DiffUtil</code> works.</strong><em>Answer:</em> <code>DiffUtil</code> is a utility class that calculates the difference between two lists and outputs a list of update operations that converts the first list into the second. It determines exactly which items were added, removed, or changed, drastically improving RecyclerView update performance compared to <code>notifyDataSetChanged()</code>.</p>',20)])])}const m=i(s,[["render",r]]);export{p as __pageData,m as default};
